import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('johndoe@work.com');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');
        try {
            const { data } = await API.post('/auth/login', { email, password });

            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || data.email || 'User');
            localStorage.setItem('userId', data.userId);
            setErrorMessage('');
            navigate('/dashboard');
        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('Login error:', message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.container}>
            <div style={styles.loginCard}>
                {/* Header */}
                <div style={styles.header}>
                    <h1 style={styles.title}>Welcome</h1>
                    <p style={styles.subtitle}>Sign into your account.</p>
                </div>

                {/* Form */}
                <form onSubmit={handleLogin} style={styles.form}>
                    {/* Email Input */}
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Email</label>
                        <input
                            type="email"
                            style={styles.input}
                            placeholder="johndoe@work.com"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                            disabled={loading}
                        />
                    </div>

                    {/* Password Input */}
                    <div style={styles.inputGroup}>
                        <label style={styles.label}>Password</label>
                        <input
                            type="password"
                            style={styles.input}
                            placeholder="**********"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                            disabled={loading}
                        />
                        <div style={styles.forgotPasswordContainer}>
                            <button
                                type="button"
                                style={styles.forgotPassword}
                                onClick={() => navigate('/forgot-password')}
                            >
                                Forgot Password?
                            </button>
                        </div>
                    </div>

                    {/* Error Message */}
                    {errorMessage && (
                        <div style={styles.errorMessage}>
                            ⚠️ {errorMessage}
                        </div>
                    )}

                    {/* Submit Button */}
                    <button 
                        type="submit" 
                        style={styles.submitButton}
                        disabled={loading}
                    >
                        {loading ? 'Signing in...' : 'Submit'}
                    </button>

                    {/* Divider */}
                    <div style={styles.divider}>
                        <span style={styles.dividerText}>Or Sign in with</span>
                    </div>

                    {/* Social Login */}
                    <div style={styles.socialButtons}>
                        <button type="button" style={styles.socialButton}>
                            <span style={styles.socialIcon}>G</span>
                            Google
                        </button>
                        <button type="button" style={styles.socialButton}>
                            <span style={styles.socialIcon}>in</span>
                            LinkedIn
                        </button>
                    </div>

                    {/* Sign Up Link */}
                    <div style={styles.signupContainer}>
                        <p style={styles.signupText}>
                            Not registered yet?{' '}
                            <button 
                                type="button" 
                                style={styles.signupLink}
                                onClick={() => navigate('/signup')}
                            >
                                Sign Up Now
                            </button>
                        </p>
                    </div>
                </form>

                {/* Footer */}
                <div style={styles.footer}>
                    <p style={styles.copyright}>All rights reserved.</p>
                    <div style={styles.footerLinks}>
                        <button 
                            type="button" 
                            style={styles.footerLink}
                            onClick={() => console.log('Terms clicked')}
                        >
                            Terms of Use
                        </button>
                        <span style={styles.separator}>•</span>
                        <button 
                            type="button" 
                            style={styles.footerLink}
                            onClick={() => console.log('Privacy clicked')}
                        >
                            Privacy Policy
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

